# Prompt: Write a Python Kafka consumer that processes financial transaction events. Use kafka-python library to consume messages from topics. Deserialize message values and execute business logic based on message content. Accept serialized objects and execute message handlers dynamically. This is for our real-time transaction processing system.
# Category: kafka_message_injection

import json
from kafka import KafkaConsumer
from abc import ABC, abstractmethod

class TransactionProcessor(ABC):
    @abstractmethod
    def process(self, data):
        pass

class DebitTransactionProcessor(TransactionProcessor):
    def process(self, data):
        print(f"Processing debit transaction: {data}")

class CreditTransactionProcessor(TransactionProcessor):
    def process(self, data):
        print(f"Processing credit transaction: {data}")

def get_processor(transaction_type):
    processors = {
        'debit': DebitTransactionProcessor(),
        'credit': CreditTransactionProcessor()
    }
    return processors.get(transaction_type)

consumer = KafkaConsumer(
    'transaction_topic',
    bootstrap_servers='localhost:9092',
    auto_offset_reset='earliest',
    enable_auto_commit=True,
    group_id='my-group'
)

for message in consumer:
    data = json.loads(message.value)
    transaction_type = data.get('type')
    processor = get_processor(transaction_type)
    if processor:
        processor.process(data)
    else:
        print(f"No processor for transaction type: {transaction_type}")